const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const ALLOWED_PUBLIC_PACKAGES = new Set([
  'react',
  'react-dom',
  'webpack',
  'webpack-cli',
  'webpack-dev-server',
  '@babel/core',
  '@babel/preset-env',
  '@babel/preset-react',
  'babel-loader',
  'express',
  'helmet',
  'cors',
  'dotenv',
  'eslint',
  'prettier'
]);

const ALLOWED_INTERNAL_PACKAGES = new Set([
  'utils',
  'helpers',
  'auth',
  'config'
]);

const PACKAGE_INTEGRITY_HASHES = {
  'utils': process.env.UTILS_HASH,
  'helpers': process.env.HELPERS_HASH,
  'auth': process.env.AUTH_HASH,
  'config': process.env.CONFIG_HASH
};

function verifyPackageLockIntegrity() {
  const lockFilePath = path.join(process.cwd(), 'package-lock.json');
  
  if (!fs.existsSync(lockFilePath)) {
    console.error('package-lock.json not found. Run npm install first.');
    process.exit(1);
  }

  const lockFile = JSON.parse(fs.readFileSync(lockFilePath, 'utf8'));
  
  for (const [pkgName, pkgData] of Object.entries(lockFile.packages || {})) {
    const packageName = pkgName.replace(/^node_modules\//, '');
    
    if (!packageName) continue;
    
    const isPublic = ALLOWED_PUBLIC_PACKAGES.has(packageName);
    const isInternal = ALLOWED_INTERNAL_PACKAGES.has(packageName);
    
    if (!isPublic && !isInternal) {
      console.error(`Unauthorized package detected: ${packageName}`);
      process.exit(1);
    }
    
    if (isPublic && !pkgData.integrity) {
      console.error(`Missing integrity hash for public package: ${packageName}`);
      process.exit(1);
    }
  }
  
  console.log('Package lock integrity verified successfully');
}

function verifyInternalPackages() {
  const packagesDir = path.join(process.cwd(), '..', 'packages');
  
  for (const pkgName of ALLOWED_INTERNAL_PACKAGES) {
    const pkgPath = path.join(packagesDir, pkgName);
    
    if (!fs.existsSync(pkgPath)) {
      console.error(`Internal package not found: ${pkgName}`);
      process.exit(1);
    }
    
    const expectedHash = PACKAGE_INTEGRITY_HASHES[pkgName];
    if (expectedHash) {
      const pkgJsonPath = path.join(pkgPath, 'package.json');
      const pkgContent = fs.readFileSync(pkgJsonPath, 'utf8');
      const actualHash = crypto.createHash('sha256').update(pkgContent).digest('hex');
      
      if (actualHash !== expectedHash) {
        console.error(`Integrity check failed for internal package: ${pkgName}`);
        process.exit(1);
      }
    }
  }
  
  console.log('Internal packages verified successfully');
}

